; EarthBound C2 loaded battle background layer config initializer.
;
; Source-emission status:
; - Prototype level: build-candidate
; - Generated by tools/emit_linear_source_module.py from a state-aware
;   linear ROM decode, then intended for byte-equivalence validation.
;
; Source units covered:
; - C2:CFE5..C2:D0AC InitLoadedBattleBgLayerFromConfig
;
; Runtime contract:
; - Initializes one `loaded_bg_data` struct from the selected
;   `BG_DATA_TABLE` layer-config row used by `LOAD_BATTLE_BG`.
; - Input A is the destination struct base (`$ADD4` or `$AE4B`); direct-page
;   `$26/$28` holds the source config-row pointer.
; - Clears the 0x77-byte runtime struct, copies bitdepth, palette-cycle style
;   and ranges, palette-change speed, four scrolling movement ids, and four
;   distortion style ids.
; - Seeds palette, scrolling, and distortion duration counters to `1` so the
;   per-frame background updater starts each lane immediately.

; ---------------------------------------------------------------------------
; External contracts used by this module

C08ED2_CopyMemoryBlock       = $C08ED2
C08EFC_ClearDestinationBlock = $C08EFC

; ---------------------------------------------------------------------------
; C2:CFE5

C2CFE5_InitLoadedBattleBgLayerFromConfig:
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFE8
    tcd
    pla
    tay
    sty $16
    lda $26
    sta $06
    lda $28
    sta $08
    lda $06
    sta $12
    lda $08
    sta $14
    sep #$20
    stz $0E
    ldx.w #$0077
    rep #$20
    tya
    ; Clear the destination loaded-bg struct before importing config fields.
    jsl C08EFC_ClearDestinationBlock
    sep #$20
    ldy.w #$0002
    ; Config byte 2 -> loaded_bg_data::bitdepth.
    lda [$06],Y
    ldy $16
    sta $0001,Y
    ldy.w #$0003
    lda [$06],Y
    ldy $16
    sta $0003,Y
    ldy.w #$0004
    lda [$06],Y
    ldy $16
    sta $0004,Y
    ldy.w #$0005
    lda [$06],Y
    ldy $16
    sta $0005,Y
    ldy.w #$0006
    lda [$06],Y
    ldy $16
    sta $0006,Y
    ldy.w #$0007
    lda [$06],Y
    ldy $16
    sta $0007,Y
    ldy.w #$0008
    ; Config byte 8 -> palette-change speed.
    lda [$06],Y
    ldy $16
    sta $000A,Y
    rep #$20
    lda.w #$0009
    clc
    adc $06
    sta $06
    sta $0E
    lda $08
    sta $10
    ldx.w #$0004
    tya
    clc
    adc.w #$004E
    ; Config bytes 9-12 -> four scrolling movement row ids.
    jsl C08ED2_CopyMemoryBlock
    lda.w #$000D
    ldx $12
    stx $06
    ldx $14
    stx $08
    clc
    adc $06
    sta $06
    sta $0E
    lda $08
    sta $10
    ldx.w #$0004
    ldy $16
